import Image from "next/image";

export default function MultiTabs() {
  return (
    <div className="max-w-7xl mt-2 mx-auto bg-gray-100 rounded-2xl p-6">
      {/* Tabs Header */}
      <div className="flex items-center justify-between mb-6">
        <div className="flex gap-6 text-sm font-medium">
          <span className="text-black">BEST SELLER</span>
          <span className="text-gray-500">NEW IN</span>
          <span className="text-gray-500">POPULAR</span>
        </div>
        <span className="text-xs text-gray-500 cursor-pointer">View All</span>
      </div>

      {/* Products Row */}
      <div className="grid grid-cols-5 gap-6">
        {[1, 2, 3, 4, 5].map((i) => (
          <div key={i} className="bg-white rounded-xl p-4 flex flex-col gap-3">
            {/* Save Badge */}
            <div className="flex justify-end">
              <span className="bg-teal-500 text-white text-xs px-2 py-1 rounded-md">
                SAVE $19.00
              </span>
            </div>

            {/* Product Image */}
            <div className="relative w-full h-32">
              <img
                src={`/headPhone.png/`}
                alt="product"
                fill
                className="object-contain"
              />
            </div>

            {/* Title */}
            <p className="text-xs text-gray-600">
              Product Title Goes Here Example Name
            </p>

            {/* Price */}
            <div className="flex items-center gap-2">
              <span className="text-green-600 font-semibold">$569.00</span>
              <span className="text-gray-400 line-through text-xs">$759.00</span>
            </div>

            {/* Tags */}
            <div className="flex gap-2 text-[10px]">
              <span className="border px-2 py-1 rounded">FREE SHIPPING</span>
              <span className="border px-2 py-1 rounded">FREE GIFT</span>
            </div>

            {/* Stock */}
            <div className="flex items-center gap-2 text-xs text-gray-500">
              <span className="w-2 h-2 bg-green-500 rounded-full"></span>
              <span>In stock</span>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
